mapper.select:
SELECT cfr.id, cfr.org_id AS orgId, cfr.clinic_id AS clinicId, c.clinic_name AS clinicName, cfr.patient_id AS patientId, p.patient_name AS patientName, cfr.medical_record_id AS medicalRecordId, mr.record_no AS medicalRecordNo, cfr.form_code AS formCode, cfr.form_name AS formName, cfr.form_content AS formContent, cfr.signer_signature_id AS signerSignatureId, cfr.doctor_signature_id AS doctorSignatureId, cfr.form_status AS formStatus, cfr.signed_at AS signedAt, cfr.created_at AS createdAt FROM consent_form_record cfr LEFT JOIN clinic c ON c.id = cfr.clinic_id LEFT JOIN patient p ON p.id = cfr.patient_id LEFT JOIN medical_record mr ON mr.id = cfr.medical_record_id WHERE cfr.org_id = #{orgId}
AND cfr.clinic_id = #{query.clinicId}
AND cfr.patient_id = #{query.patientId}
AND cfr.medical_record_id = #{query.medicalRecordId}
AND cfr.form_status = #{query.formStatus}
ORDER BY cfr.created_at DESC, cfr.id DESC
